	        "taskKind": {
	          "type": "string",
	          "minLength": 1
	        },
	        "status": {
	          "enum": [
	            "cancelled",
	            "failed",
	            "interrupted",
	            "missing",
	            "resource_blocked",
	            "succeeded",
	            "unsupported"
	          ]
	        },
	        "reason": {
	          "type": "string",
	          "minLength": 1
	        },
